+void OctomapServer::reconfigureCallback(octomap_server::OctomapServerConfig& config, uint32_t level){
+  if (m_maxTreeDepth != unsigned(config.max_depth)){
+    m_maxTreeDepth = unsigned(config.max_depth);
+
+  publishAll();
+  }
+
+
